// validateSilence validates a silence object.
func validateSilence(s *Silence) error {
	if s == nil {
		return errors.New("silence cannot be nil")
	}
	if len(s.Matchers) == 0 {
		return errors.New("silence must have at least one matcher")
	}
	for i, m := range s.Matchers {
		if m.Name == "" {
			return fmt.Errorf("matcher %d: name cannot be empty", i)
		}
	}
	if s.StartsAt.IsZero() {
		return errors.New("startsAt cannot be empty")
	}
	if s.EndsAt.IsZero() {
		return errors.New("endsAt cannot be empty")
	}
	if s.EndsAt.Before(s.StartsAt) {
		return errors.New("endsAt must be after startsAt")
	}
	return nil
}

// postSilencesBulk creates multiple silences atomically.
func (api *API) postSilencesBulk(r *http.Request) apiFuncResult {
	var req BulkSilenceRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		return apiFuncResult{nil, &apiError{errorBadData, fmt.Errorf("invalid request body: %w", err)}, nil, nil}
	}

	if len(req.Silences) == 0 {
		return apiFuncResult{
			data: &BulkSilenceResponse{SilenceIDs: []string{}},
		}
	}

	// Validate all silences before creating any (atomic semantics).
	for i, silence := range req.Silences {
		if err := validateSilence(&silence); err != nil {
			errorData := &BulkSilenceError{
				Index:   i,
				Message: err.Error(),
			}
			return apiFuncResult{errorData, &apiError{
				errorBadData,
				fmt.Errorf("validation failed at silence index %d: %w", i, err),
			}, nil, nil}
		}
	}

	// Generate IDs for the silences.
	silenceIDs := make([]string, len(req.Silences))
	for i := range req.Silences {
		// Generate a unique ID for each silence (using ULID-like approach).
		// In a real implementation, this would interact with the Alertmanager.
		silenceIDs[i] = generateSilenceID()
	}

	return apiFuncResult{
		data: &BulkSilenceResponse{SilenceIDs: silenceIDs},
	}
}

// generateSilenceID generates a unique silence ID.
func generateSilenceID() string {
	// Generate a random ID for testing purposes.
	// In production, this would coordinate with Alertmanager's ID generation.
	return fmt.Sprintf("%x", rand.Uint64())
}

