			silence: &Silence{
				Matchers: []SilenceMatcher{
					{Name: "alertname", Value: "TestAlert", IsRegex: false},
				},
				StartsAt:  validStartTime,
				EndsAt:    validEndTime,
				CreatedBy: "user",
				Comment:   "comment",
			},
			expectedErr: false,
		},
		{
			name: "no matchers",
			silence: &Silence{
				Matchers:  []SilenceMatcher{},
				StartsAt:  validStartTime,
				EndsAt:    validEndTime,
				CreatedBy: "user",
				Comment:   "comment",
			},
			expectedErr: true,
			errMessage:  "silence must have at least one matcher",
		},
		{
			name: "matcher with empty name",
			silence: &Silence{
				Matchers: []SilenceMatcher{
					{Name: "", Value: "value", IsRegex: false},
				},
				StartsAt:  validStartTime,
				EndsAt:    validEndTime,
				CreatedBy: "user",
				Comment:   "comment",
			},
			expectedErr: true,
			errMessage:  "matcher 0: name cannot be empty",
		},
		{
			name: "empty startsAt",
			silence: &Silence{
				Matchers: []SilenceMatcher{
					{Name: "alertname", Value: "TestAlert", IsRegex: false},
				},
				StartsAt:  time.Time{},
				EndsAt:    validEndTime,
				CreatedBy: "user",
				Comment:   "comment",
			},
			expectedErr: true,
			errMessage:  "startsAt cannot be empty",
		},
		{
			name: "empty endsAt",
			silence: &Silence{
				Matchers: []SilenceMatcher{
					{Name: "alertname", Value: "TestAlert", IsRegex: false},
				},
				StartsAt:  validStartTime,
				EndsAt:    time.Time{},
				CreatedBy: "user",
				Comment:   "comment",
			},
			expectedErr: true,
			errMessage:  "endsAt cannot be empty",
		},
		{
			name: "endsAt before startsAt",
			silence: &Silence{
				Matchers: []SilenceMatcher{
