func TestPostSilencesBulk(t *testing.T) {
	now := time.Now()
	startTime := now.Add(1 * time.Minute)
	endTime := now.Add(10 * time.Minute)

	testCases := []struct {
		name           string
		request        *BulkSilenceRequest
		expectedCode   int
		expectedError  string
		expectedIDs    int
		expectErrorObj *BulkSilenceError
	}{
		{
			name: "successful bulk creation with single silence",
			request: &BulkSilenceRequest{
				Silences: []Silence{
					{
						Matchers: []SilenceMatcher{
							{Name: "alertname", Value: "TestAlert", IsRegex: false},
						},
						StartsAt:  startTime,
						EndsAt:    endTime,
						CreatedBy: "test-user",
						Comment:   "test silence",
					},
				},
			},
			expectedCode: http.StatusOK,
			expectedIDs:  1,
		},
		{
			name: "successful bulk creation with multiple silences",
			request: &BulkSilenceRequest{
				Silences: []Silence{
					{
						Matchers: []SilenceMatcher{
							{Name: "alertname", Value: "Alert1", IsRegex: false},
						},
						StartsAt:  startTime,
						EndsAt:    endTime,
						CreatedBy: "user1",
						Comment:   "silence 1",
					},
					{
						Matchers: []SilenceMatcher{
							{Name: "alertname", Value: "Alert2", IsRegex: false},
							{Name: "severity", Value: "critical", IsRegex: false},
						},
						StartsAt:  startTime,
						EndsAt:    endTime,
						CreatedBy: "user2",
						Comment:   "silence 2",
					},
					{
						Matchers: []SilenceMatcher{
							{Name: "job", Value: ".*prometheus.*", IsRegex: true},
						},
						StartsAt:  startTime,
						EndsAt:    endTime,
						CreatedBy: "user3",
						Comment:   "silence 3",
					},
				},
			},
			expectedCode: http.StatusOK,
			expectedIDs:  3,
		},
		{
			name: "empty array returns empty response",
			request: &BulkSilenceRequest{
				Silences: []Silence{},
			},
			expectedCode: http.StatusOK,
			expectedIDs:  0,
		},
		{
			name: "validation failure - no matchers",
			request: &BulkSilenceRequest{
				Silences: []Silence{
					{
						Matchers:  []SilenceMatcher{},
						StartsAt:  startTime,
						EndsAt:    endTime,
						CreatedBy: "user",
						Comment:   "silence",
					},
				},
			},
			expectedCode:  http.StatusBadRequest,
			expectedError: "validation failed at silence index 0",
			expectErrorObj: &BulkSilenceError{
				Index:   0,
				Message: "silence must have at least one matcher",
			},
		},
		{
			name: "validation failure - empty matcher name",
			request: &BulkSilenceRequest{
				Silences: []Silence{
					{
						Matchers: []SilenceMatcher{
							{Name: "", Value: "value", IsRegex: false},
						},
						StartsAt:  startTime,
						EndsAt:    endTime,
						CreatedBy: "user",
						Comment:   "silence",
					},
				},
			},
			expectedCode:  http.StatusBadRequest,
			expectedError: "validation failed at silence index 0",
			expectErrorObj: &BulkSilenceError{
				Index:   0,
				Message: "matcher 0: name cannot be empty",
			},
		},
		{
			name: "validation failure - empty startsAt",
			request: &BulkSilenceRequest{
				Silences: []Silence{
					{
						Matchers: []SilenceMatcher{
							{Name: "alertname", Value: "Alert", IsRegex: false},
						},
						StartsAt:  time.Time{},
						EndsAt:    endTime,
						CreatedBy: "user",
						Comment:   "silence",
					},
				},
			},
			expectedCode:  http.StatusBadRequest,
			expectedError: "validation failed at silence index 0",
			expectErrorObj: &BulkSilenceError{
				Index:   0,
				Message: "startsAt cannot be empty",
			},
		},
		{
			name: "validation failure - empty endsAt",
			request: &BulkSilenceRequest{
				Silences: []Silence{
					{
						Matchers: []SilenceMatcher{
							{Name: "alertname", Value: "Alert", IsRegex: false},
						},
						StartsAt:  startTime,
						EndsAt:    time.Time{},
						CreatedBy: "user",
						Comment:   "silence",
					},
				},
			},
			expectedCode:  http.StatusBadRequest,
			expectedError: "validation failed at silence index 0",
			expectErrorObj: &BulkSilenceError{
				Index:   0,
				Message: "endsAt cannot be empty",
			},
		},
		{
			name: "validation failure - endsAt before startsAt",
			request: &BulkSilenceRequest{
				Silences: []Silence{
					{
						Matchers: []SilenceMatcher{
							{Name: "alertname", Value: "Alert", IsRegex: false},
						},
						StartsAt:  endTime,
						EndsAt:    startTime,
						CreatedBy: "user",
						Comment:   "silence",
					},
				},
			},
			expectedCode:  http.StatusBadRequest,
			expectedError: "validation failed at silence index 0",
			expectErrorObj: &BulkSilenceError{
				Index:   0,
				Message: "endsAt must be after startsAt",
			},
		},
		{
			name: "validation failure at index 2",
			request: &BulkSilenceRequest{
				Silences: []Silence{
					{
						Matchers: []SilenceMatcher{
							{Name: "alertname", Value: "Alert1", IsRegex: false},
						},
						StartsAt:  startTime,
						EndsAt:    endTime,
						CreatedBy: "user1",
						Comment:   "silence 1",
					},
					{
						Matchers: []SilenceMatcher{
							{Name: "alertname", Value: "Alert2", IsRegex: false},
						},
						StartsAt:  startTime,
						EndsAt:    endTime,
						CreatedBy: "user2",
						Comment:   "silence 2",
					},
					{
						Matchers:  []SilenceMatcher{},
						StartsAt:  startTime,
						EndsAt:    endTime,
						CreatedBy: "user3",
						Comment:   "silence 3",
					},
				},
			},
			expectedCode:  http.StatusBadRequest,
			expectedError: "validation failed at silence index 2",
			expectErrorObj: &BulkSilenceError{
				Index:   2,
				Message: "silence must have at least one matcher",
			},
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			api := &API{
				logger: promslog.New(&promslog.Config{}),
			}

			body, err := json.Marshal(tc.request)
			require.NoError(t, err)

			req := httptest.NewRequest("POST", "/api/v1/silences/bulk", bytes.NewReader(body))
			req.Header.Set("Content-Type", "application/json")

			result := api.postSilencesBulk(req)

			// Check error response
			if tc.expectedCode != http.StatusOK {
				require.NotNil(t, result.err)
				require.Contains(t, result.err.err.Error(), tc.expectedError)

				if tc.expectErrorObj != nil {
					// The error data contains the detailed error information
					errObj, ok := result.data.(*BulkSilenceError)
					require.True(t, ok)
					require.Equal(t, tc.expectErrorObj.Index, errObj.Index)
					require.Equal(t, tc.expectErrorObj.Message, errObj.Message)
				}
				return
			}

			// Check success response
			require.Nil(t, result.err)
			resp, ok := result.data.(*BulkSilenceResponse)
			require.True(t, ok)
			require.Len(t, resp.SilenceIDs, tc.expectedIDs)

			// All IDs should be non-empty
			for _, id := range resp.SilenceIDs {
				require.NotEmpty(t, id)
			}
		})
	}
}

func TestPostSilencesBulkInvalidJSON(t *testing.T) {
	api := &API{
		logger: promslog.New(&promslog.Config{}),
	}

	invalidJSON := []byte(`{"silences": [invalid json]}`)
	req := httptest.NewRequest("POST", "/api/v1/silences/bulk", bytes.NewReader(invalidJSON))
	req.Header.Set("Content-Type", "application/json")

	result := api.postSilencesBulk(req)

	require.NotNil(t, result.err)
	require.Contains(t, result.err.err.Error(), "invalid request body")
}

func TestPostSilencesBulkIntegration(t *testing.T) {
	api := newTestAPI(t)

	now := time.Now()
	startTime := now.Add(1 * time.Minute)
	endTime := now.Add(10 * time.Minute)

	silences := []Silence{
		{
			Matchers: []SilenceMatcher{
				{Name: "alertname", Value: "TestAlert", IsRegex: false},
			},
			StartsAt:  startTime,
			EndsAt:    endTime,
			CreatedBy: "test-user",
			Comment:   "test silence",
		},
		{
			Matchers: []SilenceMatcher{
				{Name: "severity", Value: "critical", IsRegex: false},
			},
			StartsAt:  startTime,
			EndsAt:    endTime,
			CreatedBy: "test-user",
			Comment:   "test silence 2",
		},
	}

	req := &BulkSilenceRequest{Silences: silences}
	body, err := json.Marshal(req)
	require.NoError(t, err)

	httpReq := httptest.NewRequest("POST", "/api/v1/silences/bulk", bytes.NewReader(body))
	httpReq.Header.Set("Content-Type", "application/json")

	result := api.postSilencesBulk(httpReq)

	require.Nil(t, result.err)
	resp, ok := result.data.(*BulkSilenceResponse)
	require.True(t, ok)
	require.Len(t, resp.SilenceIDs, 2)

	// Verify IDs are unique
	require.NotEqual(t, resp.SilenceIDs[0], resp.SilenceIDs[1])
}

func TestValidateSilence(t *testing.T) {
	now := time.Now()
	validStartTime := now.Add(1 * time.Minute)
	validEndTime := now.Add(10 * time.Minute)

	testCases := []struct {
		name        string
		silence     *Silence
		expectedErr bool
		errMessage  string
	}{
		{
			name:        "nil silence",
			silence:     nil,
			expectedErr: true,
			errMessage:  "silence cannot be nil",
		},
		{
			name: "valid silence",
			silence: &Silence{
				Matchers: []SilenceMatcher{
					{Name: "alertname", Value: "TestAlert", IsRegex: false},
				},
				StartsAt:  validStartTime,
				EndsAt:    validEndTime,
				CreatedBy: "user",
				Comment:   "comment",
			},
			expectedErr: false,
		},
		{
			name: "no matchers",
			silence: &Silence{
				Matchers:  []SilenceMatcher{},
				StartsAt:  validStartTime,
				EndsAt:    validEndTime,
				CreatedBy: "user",
				Comment:   "comment",
			},
			expectedErr: true,
			errMessage:  "silence must have at least one matcher",
		},
		{
			name: "matcher with empty name",
			silence: &Silence{
				Matchers: []SilenceMatcher{
					{Name: "", Value: "value", IsRegex: false},
				},
				StartsAt:  validStartTime,
				EndsAt:    validEndTime,
				CreatedBy: "user",
				Comment:   "comment",
			},
			expectedErr: true,
			errMessage:  "matcher 0: name cannot be empty",
		},
		{
			name: "empty startsAt",
			silence: &Silence{
				Matchers: []SilenceMatcher{
					{Name: "alertname", Value: "TestAlert", IsRegex: false},
				},
				StartsAt:  time.Time{},
				EndsAt:    validEndTime,
				CreatedBy: "user",
				Comment:   "comment",
			},
			expectedErr: true,
			errMessage:  "startsAt cannot be empty",
		},
		{
			name: "empty endsAt",
			silence: &Silence{
				Matchers: []SilenceMatcher{
					{Name: "alertname", Value: "TestAlert", IsRegex: false},
				},
				StartsAt:  validStartTime,
				EndsAt:    time.Time{},
				CreatedBy: "user",
				Comment:   "comment",
			},
			expectedErr: true,
			errMessage:  "endsAt cannot be empty",
		},
		{
			name: "endsAt before startsAt",
			silence: &Silence{
				Matchers: []SilenceMatcher{
					{Name: "alertname", Value: "TestAlert", IsRegex: false},
				},
				StartsAt:  validEndTime,
				EndsAt:    validStartTime,
				CreatedBy: "user",
				Comment:   "comment",
			},
			expectedErr: true,
			errMessage:  "endsAt must be after startsAt",
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			err := validateSilence(tc.silence)

			if tc.expectedErr {
				require.NotNil(t, err)
				require.Contains(t, err.Error(), tc.errMessage)
			} else {
				require.Nil(t, err)
			}
		})
	}
}

func TestGenerateSilenceID(t *testing.T) {
	// Generate multiple IDs and ensure they are unique.
	ids := make(map[string]bool)
	for i := 0; i < 100; i++ {
		id := generateSilenceID()
		require.NotEmpty(t, id)
		require.False(t, ids[id], "duplicate ID generated")
		ids[id] = true
	}
}

