func TestPostSilencesBulkWithRouter(t *testing.T) {
	api := newTestAPI(t)

	router := route.New()
	api.Register(router)

	now := time.Now()
	startTime := now.Add(1 * time.Minute)
	endTime := now.Add(10 * time.Minute)

	req := &BulkSilenceRequest{
		Silences: []Silence{
			{
				Matchers: []SilenceMatcher{
					{Name: "alertname", Value: "TestAlert", IsRegex: false},
				},
				StartsAt:  startTime,
				EndsAt:    endTime,
				CreatedBy: "test-user",
				Comment:   "test silence",
			},
		},
	}

	body, err := json.Marshal(req)
	require.NoError(t, err)

	httpReq := httptest.NewRequest("POST", "/api/v1/silences/bulk", bytes.NewReader(body))
	httpReq.Header.Set("Content-Type", "application/json")

	w := httptest.NewRecorder()
	router.ServeHTTP(w, httpReq)

	require.Equal(t, http.StatusOK, w.Code)

	var resp Response
	err = json.NewDecoder(w.Body).Decode(&resp)
	require.NoError(t, err)

	require.Equal(t, "success", string(resp.Status))
}
